VALUES
  ('cpa-moex-01401', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法相關規定，營利事業經營外銷業務，取得外匯收入者，得在不超過當年度外銷收入多少範圍 內列支特別交際應酬費？', '["1%", "2%", "3%", "5%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01402', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '他益信託契約之委託人為營利事業，依相關稅法規定，下列何者為正確？', '["受益人應將享有信託利益之權利價值，併入契約成立年度之所得額課徵所得稅", "委託人應於契約成立年度課徵贈與稅", "受益人應將享有信託利益之權利價值，於受託人依信託契約本旨交付年度併入所得額課徵所得稅", "委託人應於受託人依信託契約本旨交付年度課徵贈與稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01403', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，下列何者為營利事業計算課稅所得額時，得列為費用或損失減除的項目？', '["負責人受邀擔任與營利事業本業及附屬業務無關之上市公司獨立董事，出席會議時支出的交通費用", "購置新臺幣一百二十萬元的乘人小客車，供高階主管於上班時間洽商業務使用，按 5 年耐用年限提列 之折舊費用", "營利事業代付臺籍總經理私人住宅租金，且未將該支出列單申報總經理薪資所得", "未於限繳日期內繳清房屋稅而加徵之滯納金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01404', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法，總機構在中華民國境外之營利事業，其所得稅課徵之相關規定，下列何者正確？', '["應就中華民國境內外全部營利事業所得，合併課徵營利事業所得稅", "僅就中華民國境內之營利事業所得課徵營利事業所得稅", "若在中華民國境內有固定營業場所，應由各類所得給付人依規定之扣繳率扣繳完稅", "若在中華民國境內無固定營業場所及營業代理人，應由該營利事業依規定辦理結算申報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01405', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '營利事業下列何項不須依所得基本稅額條例規定繳納所得稅？', '["公司組織營利事業", "依規定計算之基本所得額超過新臺幣五十萬元", "所得稅結算申報有適用法律規定之投資抵減獎勵", "依所得稅法規定在中華民國境內無固定營業場所及營業代理人之營利事業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01406', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得基本稅額條例規定，申報100年度綜合所得稅時，下列何者應計入個人基本所得額？', '["捐贈土地給政府", "捐贈給某政黨的現金（該政黨該年度省（市）以上公職人員選舉之平均得票率為1.5%）", "要保人與受益人非同一人之傷害保險給付", "澳門地區來源所得新臺幣50萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01407', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，營利事業之銷貨未給與他人銷貨憑證，或未將銷貨憑證存根保存者，其法律效果如何？', '["稽徵機關得按當年度當地該項貨品之最高價格核定其銷貨價格", "稽徵機關得按當年度當地該項貨品之最低價格核定其銷貨價格", "稽徵機關得依查得之資料按同業利潤標準核定其銷貨價格", "稽徵機關得依其成本按同業利潤標準推計核定其銷貨價格"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01408', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '有關小規模營業人之敘述，下列何者正確？', '["免稅並免辦營業登記", "免稅但應辦營業登記", "應稅亦應辦理營業登記", "應稅但免辦理營業登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01409', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '稅捐稽徵法所稱相當擔保，不包括下列何項擔保品？', '["應收帳款", "黃金", "公債", "銀行存款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01410', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '有關營業人於境內提供與外銷有關之勞務者，下列敘述何者正確？', '["該項勞務收入不論是否取得外匯收入，一律應依5%計算銷項稅額", "該項勞務收入不論是否取得外匯收入，全數皆可適用零稅率", "該項勞務收入若取得外匯收入者，得依零稅率計算銷項稅額；否則應依5%計算銷項稅額", "該項勞務收入可適用免稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01411', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依營業稅法規定，進口菸品於計算其營業稅應納稅額時，其計稅價格為何？', '["不應包括菸品之菸酒稅額或菸品健康福利捐", "應包括菸品之菸酒稅額，但不包括菸品健康福利捐", "應同時包括菸品之菸酒稅額或菸品健康福利捐", "應包括菸品健康福利捐，但不包括菸品之菸酒稅額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01412', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '某公司外銷貨物未向海關申報出口，而委託國際快遞業者交寄，依營業稅法規定，下列何者不正確？', '["以國際快遞業者出據之執據，作為申報適用零稅率之證明文件", "以國際快遞業者出據之執據所載日期作為申報時點", "以國際快遞業者出據之執據所載貨物價值金額為銷售額", "以國際快遞業者出據之執據所載完稅價格核算稅額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01413', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '稅捐稽徵法對納稅義務人之財產、所得、營業及納稅等課稅資料，有關「保密」之規定，下列敘述何者 正確？', '["對所有人員及機關，應絕對保守秘密，違者應予處分", "稅捐稽徵機關對其他政府機關為統計目的，可提供資料並洩漏納稅義務人之姓名或名稱", "經財政部核定獲得租稅資訊之政府機關或人員不可就其所獲取之租稅資訊，另作其他目的使用", "財政部對重大欠稅案件或重大逃漏稅捐案件經確定後，仍不得公告欠稅人之姓名與內容"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01414', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '經復查、訴願或行政訴訟程序終結決定或判決，應補繳稅款者，稅捐稽徵機關應於復查決定，或接到訴 願決定書，或行政法院判決書正本後十日內，填發補繳稅款繳納通知書，通知納稅義務人繳納；並應按 補繳稅額，依那一年度一月一日郵政儲金一年期定期儲金固定利率，按日加計利息，一併徵收？', '["各年度", "原應繳納年度", "判決確定年度", "原復查、訴願或行政訴訟申請年度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01415', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法有關租稅之優先受償規定，下列敘述何者錯誤？', '["稅捐之徵收，優先於普通債權", "土地增值稅、地價稅、房屋稅之徵收，及法院或行政執行處拍賣、變賣貨物應課徵之營業稅，優先於 一切債權及抵押權", "破產財團成立後，其應納稅捐為財團債務，由破產管理人依公司法之規定清償之", "公司重整中所發生之稅捐，為公司重整債務，依公司法之規定清償之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01416', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，下列敘述何者錯誤？', '["本法所稱稅捐，指一切法定之國、省（市）及縣（市）稅捐；但不包括關稅及礦稅", "財政部得本互惠原則，與外國政府商訂互免稅捐，於報經行政院核准後，以外交換文方式行之", "破產財團成立後，其應納稅捐為財團費用，由破產管理人依破產法之規定清償之", "依稅法規定應自他人取得之憑證及給予他人憑證之存根或副本，應保存10年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01417', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法第31條規定，稅捐稽徵機關對逃漏下列何種稅目，涉有犯罪嫌疑之案件，得聲請當地司法 機關進行搜索？', '["所得稅及遺產稅", "營業稅及遺產稅", "所得稅及營業稅", "土地稅及房屋稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01418', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '下列何種贈與，依遺產及贈與稅法規定其財產「不計入贈與總額」內？', '["祖父贈與孫媳婦之農業用地", "父母贈與已婚子女之財產", "兄於弟結婚時贈與之現金", "夫贈與妻之財產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01419', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，遺產稅及贈與稅納稅義務人，應於稽徵機關送達核定納稅通知書之日起多少時 間內，繳清應納稅款？必要時，得於限期內申請稽徵機關核准延期多少時間？', '["30日；30日", "一個月；二個月", "二個月；二個月", "二個月；三年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01420', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '王強僅有美國籍在臺灣無住所，每年在臺灣地區賺到高額所得，最近為贈與子女資金，直接從王強德國 的帳戶匯了相當於新臺幣2,000萬元的美金進入子女在臺灣的帳戶。有關王強的匯款，依遺產及贈與稅相 關規定，下列敘述那一項正確？', '["王強的子女應該在臺灣申報綜合所得稅", "王強的子女應該申報海外所得2,000萬元，並計算所得基本稅額", "應扣除贈與年度之贈與稅免稅額後，課贈與稅", "不課贈與稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01421', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲（委託人）與乙（受託人）成立信託契約，受益人為甲，於信託關係存續中，受益人變更為丙，應於 何時課徵贈與稅？', '["信託契約成立時", "甲交付信託財產予乙時", "受益人變更時", "信託期滿乙交付信託財產予丙時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01422', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅相關法規規定，有關公共設施保留地，下列敘述何者正確？', '["所有權人（被繼承人）於公共設施保留地公告徵收後死亡，雖補償費至其死亡時尚未發給，仍應依補 償費課徵遺產稅", "所有權人（被繼承人）死亡後，公共設施保留地始公告徵收，發放給繼承人之地價補償費及加成補償 費，仍應併入被繼承人之遺產總額內課徵遺產稅", "贈與稅納稅義務人均得以受贈財產中依都市計畫法第50條之1免徵贈與稅之公共設施保留地申請抵繳 贈與稅款", "被繼承人遺產中依都市計畫法第50條之1免徵遺產稅之公共設施保留地，納稅義務人得以該項財產申 請抵繳遺產稅款"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01423', 'cpa', 'cpa-moex-103-1cd83735', 'sub-cpa-06', NULL, 'essay', '甲公司於 X1 年 7 月 1 日支付$2,400,000 取得乙公司 80%普通股股權，採權益
